#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#define MAX_ARGS 10
#define REC_LENGTH 49	
#define REC_WINDOW 10	
#define LATITUDE_POS 28	
#define OPEN 10000.0f

struct neighbor {
	char entry[REC_LENGTH];
	float dist;
};

__global__ void compute_distances(const char* sandbox, float* z, int rec_count, float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= rec_count) return;

    const char* rec_iter = sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

    // Parse latitude and longitude manually to avoid atof in kernel
    // Assuming format similar to source: fixed position strings
    float tmp_lat = 0.0f;
    float tmp_long = 0.0f;

    // Simple parsing for fixed width fields (assuming standard float formatting in string)
    // The original code uses atof on specific offsets. 
    // Offset 0 from rec_iter is latitude start. Offset 5 is longitude start.
    // We must replicate atof behavior or use a simple parser. 
    // Given the constraints and typical data, we'll use a simple conversion.

    // Re-implementing a minimal atof for CUDA
    const char* lat_str = rec_iter;
    const char* lon_str = rec_iter + 5;

    // Parse lat
    float sign = 1.0f;
    float val = 0.0f;
    float frac = 0.0f;
    float divisor = 1.0f;
    int state = 0; // 0: int part, 1: frac part

    if (*lat_str == '-') { sign = -1.0f; lat_str++; }
    else if (*lat_str == '+') { lat_str++; }

    while (*lat_str) {
        if (*lat_str == '.') {
            state = 1;
            lat_str++;
            continue;
        }
        if (*lat_str >= '0' && *lat_str <= '9') {
            int digit = *lat_str - '0';
            if (state == 0) {
                val = val * 10.0f + digit;
            } else {
                divisor *= 10.0f;
                frac += digit / divisor;
            }
        } else {
            break; // Stop at space or non-digit
        }
        lat_str++;
    }
    tmp_lat = sign * (val + frac);

    // Parse long
    sign = 1.0f;
    val = 0.0f;
    frac = 0.0f;
    divisor = 1.0f;
    state = 0;

    if (*lon_str == '-') { sign = -1.0f; lon_str++; }
    else if (*lon_str == '+') { lon_str++; }

    while (*lon_str) {
        if (*lon_str == '.') {
            state = 1;
            lon_str++;
            continue;
        }
        if (*lon_str >= '0' && *lon_str <= '9') {
            int digit = *lon_str - '0';
            if (state == 0) {
                val = val * 10.0f + digit;
            } else {
                divisor *= 10.0f;
                frac += digit / divisor;
            }
        } else {
            break;
        }
        lon_str++;
    }
    tmp_long = sign * (val + frac);

    float diff_lat = tmp_lat - target_lat;
    float diff_long = tmp_long - target_long;
    z[i] = sqrtf(diff_lat * diff_lat + diff_long * diff_long);
}

int main(int argc, char* argv[]) {
    struct timeval time0, time1;
    gettimeofday(&time0, NULL);

    FILE   *flist,*fp;
    int    i=0,j=0, k=0, rec_count=0, done=0;
    char   sandbox[REC_LENGTH * REC_WINDOW], *rec_iter, dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long;

    if(argc < 5) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if(!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = atof(argv[3]);
    target_long = atof(argv[4]);

    neighbors = (struct neighbor*)malloc(k*sizeof(struct neighbor));

    if(neighbors == NULL) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for( j = 0 ; j < k ; j++ ) { 
        neighbors[j].dist = OPEN;
    }

    if(fscanf(flist, "%s\n", dbname) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    fp = fopen(dbname, "r");
    if(!fp) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z_host = (float *) malloc(REC_WINDOW * sizeof(float));
    float *z_dev = NULL;
    char *sandbox_dev = NULL;

    cudaMalloc(&z_dev, REC_WINDOW * sizeof(float));
    cudaMalloc(&sandbox_dev, REC_LENGTH * REC_WINDOW);

    while(!done) {

        rec_count = fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
        if( rec_count != REC_WINDOW ) {
            if(!ferror(flist)) {
                fclose(fp);

                if(feof(flist))
                    done = 1;
                else {
                    if(fscanf(flist, "%s\n", dbname) != 1) {
                        fprintf(stderr, "error reading filelist\n");
                        exit(0);
                    }

                    fp = fopen(dbname, "r");

                    if(!fp) {
                        printf("error opening a db\n");
                        exit(1);
                    }
                }
            } else {
                perror("Error");
                exit(0);
            }
        }

        if (rec_count > 0) {
            // Copy data to GPU
            cudaMemcpy(sandbox_dev, sandbox, rec_count * REC_LENGTH, cudaMemcpyHostToDevice);

            // Launch kernel
            int threads_per_block = 256;
            int blocks = (rec_count + threads_per_block - 1) / threads_per_block;
            compute_distances<<<blocks, threads_per_block>>>(sandbox_dev, z_dev, rec_count, target_lat, target_long);
            cudaDeviceSynchronize();

            // Copy results back
            cudaMemcpy(z_host, z_dev, rec_count * sizeof(float), cudaMemcpyDeviceToHost);

            // Process results (finding nearest neighbors) - kept on CPU as logic is complex and k is small
            for( i = 0 ; i < rec_count ; i++ ) {
                float max_dist = -1.0f;
                int max_idx = 0;

                for( j = 0 ; j < k ; j++ ) {
                    if( neighbors[j].dist > max_dist ) {
                        max_dist = neighbors[j].dist;
                        max_idx = j;
                    }
                }

                if( z_host[i] < neighbors[max_idx].dist ) {
                    sandbox[(i+1)*REC_LENGTH-1] = '\0';
                    strcpy(neighbors[max_idx].entry, sandbox + i*REC_LENGTH);
                    neighbors[max_idx].dist = z_host[i];
                }
            }
        }
    }

    cudaFree(z_dev);
    cudaFree(sandbox_dev);

    fprintf(stderr, "The %d nearest neighbors are:\n", k);
    for( j = 0 ; j < k ; j++ ) {
        if( neighbors[j].dist != OPEN )
            fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
    }

    fclose(flist);
    free(neighbors);
    free(z_host);

    gettimeofday(&time1, NULL);
    double elapsed = (time1.tv_sec - time0.tv_sec) + (time1.tv_usec - time0.tv_usec) / 1000000.0;
    printf("total time : %15.12f s", elapsed);

    return 0;
}
